public class TypeCasting {
    public static void main(String[] args) {
        int intVal = 42;
        double doubleVal = 9.99;

        // Implicit casting: int → double (widening)
        double implicitResult; // assign intVal to a double without a cast

        // Explicit casting: double → int (narrowing)
        int explicitResult;   // cast doubleVal to int

        System.out.println("int value: " + intVal);
        System.out.println("double value: " + doubleVal);
        System.out.println("Implicit (int to double): " + implicitResult);
        System.out.println("Explicit (double to int): " + explicitResult);
    }
}

public class IntegerOverflow {
    public static void main(String[] args) {
        int maxValue = Integer.MAX_VALUE;

        System.out.println("Max int value: " + maxValue);

        // Add 1 to the maximum value
        int overflow = maxValue + 1;

        System.out.println("Max int + 1: " + overflow);
        System.out.println("Min int value: " + Integer.MIN_VALUE);
    }
}
